-- Dumping structure for view oasys.vwallpending
DROP VIEW IF EXISTS `vwallpending`;
-- Removing temporary table and create final VIEW structure
DROP TABLE IF EXISTS `vwallpending`;
CREATE ALGORITHM=UNDEFINED DEFINER=`planning`@`%` VIEW `vwallpending` AS select a.*,r.fullname as Reqby, e.company_id,r.companyname,r.departmentname,r.requeststatus,p.sequence,e.FullName from tbl_dayoffapproval a left join vwdayoffreq r on a.dayoff_id=r.id left join tbl_approver p on a.approver_id=p.id left join tbl_employee e on p.employee_id=e.id where a.ApprovalStatus=0 order by a.dayoff_id, p.sequence ;


-- Dumping structure for view oasys.vwdayoffreq
DROP VIEW IF EXISTS `vwdayoffreq`;
-- Removing temporary table and create final VIEW structure
DROP TABLE IF EXISTS `vwdayoffreq`;
CREATE ALGORITHM=UNDEFINED DEFINER=`planning`@`%` VIEW `vwdayoffreq` AS select 
	dr.id,
	dr.RequestDate,
	dr.RequestStatus,
	case when dr.RequestStatus='0' then 'Saved as Draft' 
		  when dr.RequestStatus='1' then 'Waiting Approval' 
		  when dr.RequestStatus='2' then 'Require Rework' 
		  when dr.RequestStatus='3' then 'Approved' 
		  when dr.RequestStatus='4' then 'Rejected' 
		  else '' end as ReqStatus,  
	dr.employee_id,
	em.FullName,
	dr.superior,
	sp.FullName as SuperiorName,
	dr.depthead,
	dh.FullName as DeptHeadName,
	em.SAPID,
	c.companyname ,
	d.DepartmentName,
	dr.ApprovedDoc,
	dr.Remarks
from tbl_dayoffreq dr 
left join tbl_employee em on dr.employee_id=em.id 
left join tbl_company c on em.company_id=c.id 
left join tbl_department d on em.department_id=d.id 
left join tbl_employee sp on dr.superior=sp.id
left join tbl_employee dh on dr.depthead=dh.id ;


