-- Dumping structure for view oasys.vwrfcreport
DROP VIEW IF EXISTS `vwrfcreport`;
-- Removing temporary table and create final VIEW structure
DROP TABLE IF EXISTS `vwrfcreport`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` VIEW `vwrfcreport` AS select 
	r.*,
	e.FullName as RequestBy,
	d.DepartmentName as Department,
	a.ActivityDescr as KindOfContract,
	c1.ContractorName as ContractorRecom1,
	c2.ContractorName as ContractorRecom2,
	case
		when r.RequestStatus='0' then 'Saved as Draft'
		when r.RequestStatus='1' then 
		 concat('Waiting Approval',
		 			case
					 	when r.apprdeptheaddate is null and r.apprdeptheadname is not null then ' Dept Head'
					 	when r.apprcadbudate is null and r.apprcadbuname is not null then ' CAD BU'
					 	when r.apprcadkfdate is null and r.apprcadkfname is not null then ' CAD KF'
					 	when r.apprhrddate is null and r.apprhrdname is not null then 'HRD BU'
					 	when r.apprhrkfdate is null and r.apprhrkfname is not null then 'HRD KF'
					 	when r.apprfcbudate is null and r.apprfcbuname is not null then ' FC BU'
					 	when r.apprbuheaddate is null and r.apprbuheadname is not null then ' BU Head'
					 	when r.apprcpudate is null and r.apprcpuname is not null then ' CPU'
					 	when r.apprkffcdate is null and r.apprkffcname is not null then ' FC KF'
					 	when r.apprmdkfdate is null and r.apprmdkfname is not null then ' MD KF'
						else ''
					end
				)
		when r.RequestStatus='2' then 'Require Rework'
		when r.RequestStatus='3' then 'Approved'
		when r.RequestStatus='4' then 'Rejected'
		else ''
	end as LastStatus
from vwrfcreportsubquery r
	left join tbl_employee e on r.employee_id = e.id
	left join tbl_department d on e.department_id = d.id
	left join tbl_rfcactivity a on r.activity_id = a.id
	left join tbl_rfccontractor c1 on r.contractor_id = c1.id
	left join tbl_rfccontractor c2 on r.contractor_id = c2.id ;


-- Dumping structure for view oasys.vwrfcreportsubquery
DROP VIEW IF EXISTS `vwrfcreportsubquery`;
-- Removing temporary table and create final VIEW structure
DROP TABLE IF EXISTS `vwrfcreportsubquery`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` VIEW `vwrfcreportsubquery` AS select 
	r.*,
	d.fullname as ApprDeptHeadName,
	case 
		when d.approvalstatus='0' then 'Waiting Approval' 
		when d.approvalstatus='1' then 'Rework' 
		when d.ApprovalStatus='2' then 'Approved' 
		when d.approvalstatus='3' then 'Rejected' 
		else '' 
	end as ApprDeptHeadStatus, 
	case 
		when not(d.ApprovalStatus in ('0','4')) then d.ApprovalDate 
		else null 
	end as ApprDeptHeadDate,
	c.fullname as ApprCADBUName,
	case 
		when c.approvalstatus='0' then 'Waiting Approval' 
		when c.approvalstatus='1' then 'Rework' 
		when c.ApprovalStatus='2' then 'Approved' 
		when c.approvalstatus='3' then 'Rejected' 
		else '' 
	end as ApprCADBUStatus, 
	case 
		when not(c.ApprovalStatus in ('0','4')) then c.ApprovalDate 
		else null 
	end as ApprCADBUDate,
	h.fullname as ApprHRDName,
	case 
		when h.approvalstatus='0' then 'Waiting Approval' 
		when h.approvalstatus='1' then 'Rework' 
		when h.ApprovalStatus='2' then 'Approved' 
		when h.approvalstatus='3' then 'Rejected' 
		else '' 
	end as ApprHRDStatus, 
	case 
		when not(h.ApprovalStatus in ('0','4')) then h.ApprovalDate 
		else null 
	end as ApprHRDDate,
	hk.fullname as ApprHRKFName,
	case 
		when hk.approvalstatus='0' then 'Waiting Approval' 
		when hk.approvalstatus='1' then 'Rework' 
		when hk.ApprovalStatus='2' then 'Approved' 
		when hk.approvalstatus='3' then 'Rejected' 
		else '' 
	end as ApprHRKFStatus, 
	case 
		when not(hk.ApprovalStatus in ('0','4')) then hk.ApprovalDate 
		else null 
	end as ApprHRKFDate ,
	ck.fullname as ApprCADKFName,
	case 
		when ck.approvalstatus='0' then 'Waiting Approval' 
		when ck.approvalstatus='1' then 'Rework' 
		when ck.ApprovalStatus='2' then 'Approved' 
		when ck.approvalstatus='3' then 'Rejected' 
		else '' 
	end as ApprCADKFStatus, 
	case 
		when not(ck.ApprovalStatus in ('0','4')) then ck.ApprovalDate 
		else null 
	end as ApprCADKFDate ,
	fb.fullname as ApprFCBUName,
	case 
		when fb.approvalstatus='0' then 'Waiting Approval' 
		when fb.approvalstatus='1' then 'Rework' 
		when fb.ApprovalStatus='2' then 'Approved' 
		when fb.approvalstatus='3' then 'Rejected' 
		else '' 
	end as ApprFCBUStatus, 
	case 
		when not(fb.ApprovalStatus in ('0','4')) then fb.ApprovalDate 
		else null 
	end as ApprFCBUDate,
	bh.fullname as ApprBUHeadName,
	case 
		when bh.approvalstatus='0' then 'Waiting Approval' 
		when bh.approvalstatus='1' then 'Rework' 
		when bh.ApprovalStatus='2' then 'Approved' 
		when bh.approvalstatus='3' then 'Rejected' 
		else '' 
	end as ApprBUHeadStatus, 
	case 
		when not(bh.ApprovalStatus in ('0','4')) then bh.ApprovalDate 
		else null 
	end as ApprBUHeadDate,
	cpu.fullname as ApprCPUName,
	case 
		when cpu.approvalstatus='0' then 'Waiting Approval' 
		when cpu.approvalstatus='1' then 'Rework' 
		when cpu.ApprovalStatus='2' then 'Approved' 
		when cpu.approvalstatus='3' then 'Rejected' 
		else '' 
	end as ApprCPUStatus, 
	case 
		when not(cpu.ApprovalStatus in ('0','4')) then cpu.ApprovalDate 
		else null 
	end as ApprCPUDate,
	kfc.fullname as ApprKFFCName,
	case 
		when kfc.approvalstatus='0' then 'Waiting Approval' 
		when kfc.approvalstatus='1' then 'Rework' 
		when kfc.ApprovalStatus='2' then 'Approved' 
		when kfc.approvalstatus='3' then 'Rejected' 
		else '' 
	end as ApprKFFCStatus, 
	case 
		when not(kfc.ApprovalStatus in ('0','4')) then kfc.ApprovalDate 
		else null 
	end as ApprKFFCDate,
	m.fullname as ApprMDKFName,
	case 
		when m.approvalstatus='0' then 'Waiting Approval' 
		when m.approvalstatus='1' then 'Rework' 
		when m.ApprovalStatus='2' then 'Approved' 
		when m.approvalstatus='3' then 'Rejected' 
		else '' 
	end as ApprMDKFStatus, 
