		when not(m.ApprovalStatus in ('0','4')) then m.ApprovalDate 
		else null 
	end as ApprMDKFDate
from tbl_rfc r 
	left join vwrfcapprovedepthead d on r.id=d.rfc_id
	left join vwrfcapprovecadbu c on r.id=c.rfc_id
	left join vwrfcapprovecadkf ck on r.id=ck.rfc_id
	left join vwrfcapprovehrd h on r.id=h.rfc_id
	left join vwrfcapprovehrkf hk on r.id=hk.rfc_id
	left join vwrfcapprovebufc fb on r.id=fb.rfc_id
	left join vwrfcapprovebuhead bh on r.id=bh.rfc_id
	left join vwrfcapprovecpu cpu on r.id=cpu.rfc_id
	left join vwrfcapprovekffc kfc on r.id=kfc.rfc_id
	left join vwrfcapprovemdkf m on r.id=m.rfc_id ;
